#include<bits/stdc++.h>
using namespace std;
long long n,q,k;
vector<pair<long long,long long>> mp[100010];
long long dis[100010],dis_t[100010],d[100010],lg[100010];
long long fa[100010][21],min1[100010][21];
bool vis[100010];
void dijkstra()
{
    memset(dis,0x3f,sizeof(dis));
    memset(vis,0,sizeof(vis));
    priority_queue<pair<long long,long long>> q;
    for(long long i=1;i<=k;i++)
    {
        long long x;
        scanf("%lld",&x);
        dis[x]=0;
        q.push(make_pair(0,x));
    }
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
}
void dfs(long long x,long long f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    min1[x][0]=dis[x];
    for(long long i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
        min1[x][i]=min(min1[fa[x][i-1]][i-1],min1[x][i-1]);
    }
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=f)
        {
            dis_t[v]=dis_t[x]+val;
            dfs(v,x);
        }
    }
}
long long getans(long long u,long long v)
{
    long long ans=1e18,tmp=dis_t[u]+dis_t[v];
    if(d[u]<d[v])
    {
        swap(u,v);
    }
    while(d[u]>d[v])
    {
        ans=min(ans,min1[u][lg[d[u]-d[v]]]);
        u=fa[u][lg[d[u]-d[v]]];
    }
    if(u==v)
    {
        return min(ans,dis[u])*2+tmp-dis_t[u]*2;
    }
    for(long long i=lg[d[u]];i>=0;i--)
    {
        if(fa[u][i]!=fa[v][i])
        {
            ans=min({ans,min1[u][i],min1[v][i]});
            u=fa[u][i];
            v=fa[v][i];
        }
    }
    ans=min({ans,dis[u],dis[v]});
    u=fa[u][0];
    return min(ans,dis[u])*2+tmp-dis_t[u]*2;
}
int main()
{
    min1[0][0]=1e18;
    scanf("%lld%lld%lld",&n,&q,&k);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dijkstra();
    dfs(1);
    while(q--)
    {
        long long s,t;
        scanf("%lld%lld",&s,&t);
        printf("%lld\n",getans(s,t));
    }
    return 0;
}
